import{_ as s,c as a,d as e,o as p}from"./app-ClFPPuY-.js";const l="/assets/images/bazel/gazelle_run.png",t={};function i(o,n){return p(),a("div",null,[...n[0]||(n[0]=[e(`<h1 id="使用-bazel-创建go应用程序的docker容器镜像" tabindex="-1"><a class="header-anchor" href="#使用-bazel-创建go应用程序的docker容器镜像"><span>使用 Bazel 创建Go应用程序的Docker容器镜像</span></a></h1><p>如果你知道<a href="https://bazel.build/" target="_blank" rel="noopener noreferrer">Bazel</a>，你就会知道它有多棒：它快速可靠。当您在使用多种服务的项目中工作时，甚至可能使用不同的语言，拥有一个快速可靠的构建系统，更重要的是，生成<a href="https://bazel.build/faq.html#why-would-i-want-to-use-bazel" target="_blank" rel="noopener noreferrer">确定性构建</a>是关键。</p><p>但是，您可能不知道使用它<code>bazel</code>来构建容器镜像是多么容易。您将从使用<code>bazel</code>应用到您的镜像构建过程中获得所有好处。另外，您不必处理丑陋的<code>Dockerfiles</code>。</p><p>如果您想了解如何实施 <code>bazel</code> 来构建您的 <code>docker</code> 镜像，请继续阅读。</p><h2 id="示例项目" tabindex="-1"><a class="header-anchor" href="#示例项目"><span>示例项目</span></a></h2><blockquote><p>您可以在 GitHub 中查看最终代码及其所有提交：</p><p><a href="https://github.com/tx7do/bazel-containers-hasher-example" target="_blank" rel="noopener noreferrer">https://github.com/tx7do/bazel-containers-hasher-example</a></p></blockquote><p>我们的项目是一个用于密码加密和验证的 API。它将有两个接口：</p><h3 id="post-hash" tabindex="-1"><a class="header-anchor" href="#post-hash"><span>POST <code>/hash</code></span></a></h3><p>请求数据Body：</p><div class="language-json line-numbers-mode" data-highlighter="prismjs" data-ext="json"><pre><code><span class="line"><span class="token punctuation">{</span><span class="token property">&quot;plain&quot;</span><span class="token operator">:</span> <span class="token string">&quot;string to hash&quot;</span><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>返回数据：</p><div class="language-json line-numbers-mode" data-highlighter="prismjs" data-ext="json"><pre><code><span class="line"><span class="token punctuation">{</span><span class="token property">&quot;hashed&quot;</span><span class="token operator">:</span> <span class="token string">&quot;hashed string&quot;</span><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="post-compare" tabindex="-1"><a class="header-anchor" href="#post-compare"><span>POST <code>/compare</code></span></a></h3><p>请求数据Body：</p><div class="language-json line-numbers-mode" data-highlighter="prismjs" data-ext="json"><pre><code><span class="line"><span class="token punctuation">{</span><span class="token property">&quot;hashed&quot;</span><span class="token operator">:</span> <span class="token string">&quot;hashed string&quot;</span><span class="token punctuation">,</span> <span class="token property">&quot;compare_to&quot;</span><span class="token operator">:</span> <span class="token string">&quot;plaintext string&quot;</span><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>返回数据：</p><ul><li><code>200 Ok</code> 如果 <code>compare_to</code> 的值等于 <code>hashed</code> 的值。</li><li><code>406 Not Acceptable</code> 不成功返回。</li></ul><h2 id="新建一个-bazel-项目" tabindex="-1"><a class="header-anchor" href="#新建一个-bazel-项目"><span>新建一个 bazel 项目</span></a></h2><p>对于本指南，我们假设您已经安装并配置了<a href="https://docs.bazel.build/versions/master/install.html" target="_blank" rel="noopener noreferrer">Bazel</a>和<a href="https://help.github.com/en/github/getting-started-with-github/set-up-git" target="_blank" rel="noopener noreferrer">Git</a>。我们的项目文件将保存在<code>$GOPATH/src/github.com/{username}/examples-bazel-containers-hasher</code>（请记住替换<code>{username}</code>为您的实际 GitHub 用户名）。让我们从创建项目文件夹并启动 Git 代码库开始：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">mkdir</span> <span class="token parameter variable">-p</span> <span class="token variable">$GOPATH</span>/src/github.com/schoren/examples-bazel-containers-hasher</span>
<span class="line"></span>
<span class="line"><span class="token builtin class-name">cd</span> <span class="token variable">$GOPATH</span>/src/github.com/schoren/examples-bazel-containers-hasher</span>
<span class="line"></span>
<span class="line"><span class="token function">git</span> init <span class="token builtin class-name">.</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>现在，让我们设置 Bazel，以便它可以在 go 中构建一个简单的 Hello World 程序。为此，我们必须在项目根目录中创建一个<code>WORKSPACE</code>文件，并加载<code>rules_go</code>，包括 <code>Gazelle</code>：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line"><span class="token comment">## General rules</span></span>
<span class="line">load<span class="token punctuation">(</span><span class="token string">&quot;@bazel_tools//tools/build_defs/repo:http.bzl&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;http_archive&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">## rules_go</span></span>
<span class="line">http_archive<span class="token punctuation">(</span></span>
<span class="line">    name <span class="token operator">=</span> <span class="token string">&quot;io_bazel_rules_go&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    sha256 <span class="token operator">=</span> <span class="token string">&quot;142dd33e38b563605f0d20e89d9ef9eda0fc3cb539a14be1bdb1350de2eda659&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    urls <span class="token operator">=</span> <span class="token punctuation">[</span></span>
<span class="line">        <span class="token string">&quot;https://mirror.bazel.build/github.com/bazelbuild/rules_go/releases/download/v0.22.2/rules_go-v0.22.2.tar.gz&quot;</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token string">&quot;https://github.com/bazelbuild/rules_go/releases/download/v0.22.2/rules_go-v0.22.2.tar.gz&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">load<span class="token punctuation">(</span><span class="token string">&quot;@io_bazel_rules_go//go:deps.bzl&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;go_register_toolchains&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;go_rules_dependencies&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">go_rules_dependencies<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">go_register_toolchains<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">## Gazelle</span></span>
<span class="line">http_archive<span class="token punctuation">(</span></span>
<span class="line">    name <span class="token operator">=</span> <span class="token string">&quot;bazel_gazelle&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    sha256 <span class="token operator">=</span> <span class="token string">&quot;d8c45ee70ec39a57e7a05e5027c32b1576cc7f16d9dd37135b0eddde45cf1b10&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    urls <span class="token operator">=</span> <span class="token punctuation">[</span></span>
<span class="line">        <span class="token string">&quot;https://storage.googleapis.com/bazel-mirror/github.com/bazelbuild/bazel-gazelle/releases/download/v0.20.0/bazel-gazelle-v0.20.0.tar.gz&quot;</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token string">&quot;https://github.com/bazelbuild/bazel-gazelle/releases/download/v0.20.0/bazel-gazelle-v0.20.0.tar.gz&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">load<span class="token punctuation">(</span><span class="token string">&quot;@bazel_gazelle//:deps.bzl&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;gazelle_dependencies&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">gazelle_dependencies<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Gazelle 需要你在项目根目录设置一个<code>BUILD.bazel</code>文件来定义<code>//:gazelle</code>目标，并设置基础包名称：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line">load<span class="token punctuation">(</span><span class="token string">&quot;@bazel_gazelle//:def.bzl&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;gazelle&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">## This is a gazelle anotation, change the package </span></span>
<span class="line"><span class="token comment"># gazelle:prefix github.com/schoren/example-bazel-containers-hasher</span></span>
<span class="line">gazelle<span class="token punctuation">(</span>name <span class="token operator">=</span> <span class="token string">&quot;gazelle&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>要拉取所有新添加的Bazel依赖项，只需运行 Gazelle 就可以了：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">bazel run //:gazelle</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p><img src="`+l+`" alt="gazelle_run"></p><p>Bazel 在工作区根目录中生成和管理一些文件夹，这些文件夹不应提交到版本控制中，因此，让我们创建一个<code>.gitignore</code>文件，并添加以下内容：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">/bazel-*</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>提交您的更改：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">git</span> <span class="token function">add</span> <span class="token builtin class-name">.</span></span>
<span class="line"><span class="token function">git</span> commit <span class="token parameter variable">-m</span> <span class="token string">&quot;Setup Bazel with rules_go and Gazelle&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="添加一个-hello-world-示例代码" tabindex="-1"><a class="header-anchor" href="#添加一个-hello-world-示例代码"><span>添加一个 hello world 示例代码</span></a></h2><p>现在，让我们为我们的程序创建基本的项目结构。由于本文的重点是 docker 部分，因此我们不会过多介绍 go 代码。</p><p>我们将使用<a href="https://github.com/gorilla/mux" target="_blank" rel="noopener noreferrer">Gorilla Mux</a>来进行HTTP路由处理，并使用<code>net/http</code>作为HTTP服务器实际所使用的go包。</p><p>首先，让我们为这个程序初始化<code>go mod</code>，它将处理我们的go依赖项：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">go mod init</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>现在，让我们在<code>cmd/api</code>文件夹中创建一个<code>main</code>函数：</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">package</span> main</span>
<span class="line"></span>
<span class="line"><span class="token keyword">import</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token string">&quot;encoding/json&quot;</span></span>
<span class="line">    <span class="token string">&quot;log&quot;</span></span>
<span class="line">    <span class="token string">&quot;net/http&quot;</span></span>
<span class="line">    <span class="token string">&quot;time&quot;</span></span>
<span class="line"></span>
<span class="line">    <span class="token string">&quot;github.com/gorilla/mux&quot;</span></span>
<span class="line">    <span class="token string">&quot;golang.org/x/crypto/bcrypt&quot;</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    r <span class="token operator">:=</span> mux<span class="token punctuation">.</span><span class="token function">NewRouter</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    r<span class="token punctuation">.</span><span class="token function">HandleFunc</span><span class="token punctuation">(</span><span class="token string">&quot;/hash&quot;</span><span class="token punctuation">,</span> hashHandler<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Methods</span><span class="token punctuation">(</span>http<span class="token punctuation">.</span>MethodPost<span class="token punctuation">)</span></span>
<span class="line">    r<span class="token punctuation">.</span><span class="token function">HandleFunc</span><span class="token punctuation">(</span><span class="token string">&quot;/compare&quot;</span><span class="token punctuation">,</span> compareHandler<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Methods</span><span class="token punctuation">(</span>http<span class="token punctuation">.</span>MethodPost<span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">    srv <span class="token operator">:=</span> <span class="token operator">&amp;</span>http<span class="token punctuation">.</span>Server<span class="token punctuation">{</span></span>
<span class="line">        Handler<span class="token punctuation">:</span>      r<span class="token punctuation">,</span></span>
<span class="line">        Addr<span class="token punctuation">:</span>         <span class="token string">&quot;:8000&quot;</span><span class="token punctuation">,</span></span>
<span class="line">        WriteTimeout<span class="token punctuation">:</span> <span class="token number">1</span> <span class="token operator">*</span> time<span class="token punctuation">.</span>Second<span class="token punctuation">,</span></span>
<span class="line">        ReadTimeout<span class="token punctuation">:</span>  <span class="token number">1</span> <span class="token operator">*</span> time<span class="token punctuation">.</span>Second<span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">    log<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span><span class="token string">&quot;Start serving...&quot;</span><span class="token punctuation">)</span></span>
<span class="line">    log<span class="token punctuation">.</span><span class="token function">Fatal</span><span class="token punctuation">(</span>srv<span class="token punctuation">.</span><span class="token function">ListenAndServe</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">type</span> hashRequest <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    Plain <span class="token builtin">string</span> <span class="token string">\`json:&quot;plain&quot;\`</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">type</span> hashResponse <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    Hashed <span class="token builtin">string</span> <span class="token string">\`json:&quot;hashed&quot;\`</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">hashHandler</span><span class="token punctuation">(</span>w http<span class="token punctuation">.</span>ResponseWriter<span class="token punctuation">,</span> r <span class="token operator">*</span>http<span class="token punctuation">.</span>Request<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    req <span class="token operator">:=</span> hashRequest<span class="token punctuation">{</span><span class="token punctuation">}</span></span>
<span class="line">    err <span class="token operator">:=</span> json<span class="token punctuation">.</span><span class="token function">NewDecoder</span><span class="token punctuation">(</span>r<span class="token punctuation">.</span>Body<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Decode</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>req<span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">        log<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;Cannot decode hashRequest: %s&quot;</span><span class="token punctuation">,</span> err<span class="token punctuation">.</span><span class="token function">Error</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">        w<span class="token punctuation">.</span><span class="token function">WriteHeader</span><span class="token punctuation">(</span>http<span class="token punctuation">.</span>StatusBadRequest<span class="token punctuation">)</span></span>
<span class="line">        <span class="token keyword">return</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">    hashedBytes<span class="token punctuation">,</span> err <span class="token operator">:=</span> bcrypt<span class="token punctuation">.</span><span class="token function">GenerateFromPassword</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token function">byte</span><span class="token punctuation">(</span>req<span class="token punctuation">.</span>Plain<span class="token punctuation">)</span><span class="token punctuation">,</span> bcrypt<span class="token punctuation">.</span>DefaultCost<span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">        log<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;Cannot encrypt password: %s&quot;</span><span class="token punctuation">,</span> err<span class="token punctuation">.</span><span class="token function">Error</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">        w<span class="token punctuation">.</span><span class="token function">WriteHeader</span><span class="token punctuation">(</span>http<span class="token punctuation">.</span>StatusInternalServerError<span class="token punctuation">)</span></span>
<span class="line">        <span class="token keyword">return</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">    resp<span class="token punctuation">,</span> err <span class="token operator">:=</span> json<span class="token punctuation">.</span><span class="token function">Marshal</span><span class="token punctuation">(</span>hashResponse<span class="token punctuation">{</span>Hashed<span class="token punctuation">:</span> <span class="token function">string</span><span class="token punctuation">(</span>hashedBytes<span class="token punctuation">)</span><span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">        log<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;Cannot marshal response json: %s&quot;</span><span class="token punctuation">,</span> err<span class="token punctuation">.</span><span class="token function">Error</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">        w<span class="token punctuation">.</span><span class="token function">WriteHeader</span><span class="token punctuation">(</span>http<span class="token punctuation">.</span>StatusInternalServerError<span class="token punctuation">)</span></span>
<span class="line">        <span class="token keyword">return</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">    w<span class="token punctuation">.</span><span class="token function">Header</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Set</span><span class="token punctuation">(</span><span class="token string">&quot;Content-Type&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;application/json&quot;</span><span class="token punctuation">)</span></span>
<span class="line">    w<span class="token punctuation">.</span><span class="token function">WriteHeader</span><span class="token punctuation">(</span>http<span class="token punctuation">.</span>StatusOK<span class="token punctuation">)</span></span>
<span class="line">    w<span class="token punctuation">.</span><span class="token function">Write</span><span class="token punctuation">(</span>resp<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">type</span> compareRequest <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    Hashed    <span class="token builtin">string</span> <span class="token string">\`json:&quot;hashed&quot;\`</span></span>
<span class="line">    CompareTo <span class="token builtin">string</span> <span class="token string">\`json:&quot;compare_to&quot;\`</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">compareHandler</span><span class="token punctuation">(</span>w http<span class="token punctuation">.</span>ResponseWriter<span class="token punctuation">,</span> r <span class="token operator">*</span>http<span class="token punctuation">.</span>Request<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    req <span class="token operator">:=</span> compareRequest<span class="token punctuation">{</span><span class="token punctuation">}</span></span>
<span class="line">    err <span class="token operator">:=</span> json<span class="token punctuation">.</span><span class="token function">NewDecoder</span><span class="token punctuation">(</span>r<span class="token punctuation">.</span>Body<span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Decode</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>req<span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">        log<span class="token punctuation">.</span><span class="token function">Printf</span><span class="token punctuation">(</span><span class="token string">&quot;Cannot decode compareRequest: %s&quot;</span><span class="token punctuation">,</span> err<span class="token punctuation">.</span><span class="token function">Error</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">        w<span class="token punctuation">.</span><span class="token function">WriteHeader</span><span class="token punctuation">(</span>http<span class="token punctuation">.</span>StatusBadRequest<span class="token punctuation">)</span></span>
<span class="line">        <span class="token keyword">return</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">    err <span class="token operator">=</span> bcrypt<span class="token punctuation">.</span><span class="token function">CompareHashAndPassword</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token function">byte</span><span class="token punctuation">(</span>req<span class="token punctuation">.</span>Hashed<span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token function">byte</span><span class="token punctuation">(</span>req<span class="token punctuation">.</span>CompareTo<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token comment">// the only error we can have here is if there&#39;s not a match</span></span>
<span class="line">    <span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">        w<span class="token punctuation">.</span><span class="token function">WriteHeader</span><span class="token punctuation">(</span>http<span class="token punctuation">.</span>StatusUnauthorized<span class="token punctuation">)</span></span>
<span class="line">        <span class="token keyword">return</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">    w<span class="token punctuation">.</span><span class="token function">WriteHeader</span><span class="token punctuation">(</span>http<span class="token punctuation">.</span>StatusOK<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>初始化go mod和构建配置依赖项。这是需要的，这样包就可以使用标准的go工具。然后我们将使用<code>gazelle</code>同步 Bazel 依赖项。</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">go mod tidy</span>
<span class="line"></span>
<span class="line">bazel run //:gazelle -- update-repos <span class="token parameter variable">-from_file</span><span class="token operator">=</span>go.mod</span>
<span class="line">bazel run //:gazelle</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>go mod tidy</code>命令更新<code>go.mod</code>和<code>go.sum</code>依赖文件。</p><p>然后，我们使用<code>gazelle</code>导入<code>go.mod</code>依赖项，并将它们插入到<code>WORKSPACE</code>文件中。</p><p>最后，我们在<code>gazelle</code>没有任何参数的情况下运行，以创建或更新所有必需的<code>BUILD.bazel</code>文件。</p><p>现在，我们应该是能够使用bazel来执行构建和运行项目：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">bazel build //<span class="token punctuation">..</span>.</span>
<span class="line">bazel run //cmd/api</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>为了测试一切是否按预期工作，我们可以<code>curl</code>在不同的终端中使用：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">$ <span class="token function">curl</span> <span class="token parameter variable">-i</span> localhost:8000/hash <span class="token parameter variable">-d</span> <span class="token string">&#39;{&quot;plain&quot;:&quot;text&quot;}&#39;</span></span>
<span class="line">HTTP/1.1 <span class="token number">200</span> OK</span>
<span class="line">Content-Type: application/json</span>
<span class="line">Content-Length: <span class="token number">73</span></span>
<span class="line"></span>
<span class="line"><span class="token punctuation">{</span><span class="token string">&quot;hashed&quot;</span><span class="token builtin class-name">:</span><span class="token string">&quot;<span class="token variable">$2a</span><span class="token variable">$10</span><span class="token variable">$ZqRE</span>.vvvpjHYHvp8HFHO7eGg6RRUS//ctlYPU5sqMYKYzjhAsJIsu&quot;</span><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">$ <span class="token function">curl</span> <span class="token parameter variable">-i</span> localhost:8000/compare <span class="token parameter variable">-d</span> <span class="token string">&#39;{&quot;hashed&quot;:&quot;$2a$10$ZqRE.vvvpjHYHvp8HFHO7eGg6RRUS//ctlYPU5sqMYKYzjhAsJIsu&quot;,&quot;compare_to&quot;:&quot;text&quot;}&#39;</span></span>
<span class="line">HTTP/1.1 <span class="token number">200</span> OK</span>
<span class="line">Content-Length: <span class="token number">0</span></span>
<span class="line"></span>
<span class="line">$ <span class="token function">curl</span> <span class="token parameter variable">-i</span> localhost:8000/compare <span class="token parameter variable">-d</span> <span class="token string">&#39;{&quot;hashed&quot;:&quot;$2a$10$ZqRE.vvvpjHYHvp8HFHO7eGg6RRUS//ctlYPU5sqMYKYzjhAsJIsu&quot;,&quot;compare_to&quot;:&quot;invalid&quot;}&#39;</span></span>
<span class="line"><span class="token number">401</span> Unauthorized</span>
<span class="line">Content-Length: <span class="token number">0</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>好的！我们可以提交我们的代码：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">git</span> <span class="token function">add</span> <span class="token builtin class-name">.</span></span>
<span class="line"><span class="token function">git</span> commit <span class="token parameter variable">-m</span> <span class="token string">&quot;Add go api code&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>现在让我们看看如何为这个应用程序构建一个 docker 容器。</p><h2 id="添加docker支持" tabindex="-1"><a class="header-anchor" href="#添加docker支持"><span>添加Docker支持</span></a></h2><p>我们将使用<a href="https://github.com/bazelbuild/rules_docker" target="_blank" rel="noopener noreferrer">rules_docker</a>创建容器镜像。这个包提供了构建 通用镜像 以及 <a href="https://github.com/bazelbuild/rules_docker#language-rules" target="_blank" rel="noopener noreferrer">特定语言镜像</a> 的规则。我们可以使用<code>go_image</code>方法，但正如文档中所述，它在 Mac 中不起作用，而且我们不想强迫开发人员限制使用任何特定操作系统，因此我们必须使用更通用的<a href="https://github.com/bazelbuild/rules_docker#container_image-1" target="_blank" rel="noopener noreferrer">container_image</a>方法。</p><p>首先，我们必须在我们的<code>WORKSPACE</code>文件中加载规则：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line"><span class="token comment">## General rules</span></span>
<span class="line">load<span class="token punctuation">(</span><span class="token string">&quot;@bazel_tools//tools/build_defs/repo:http.bzl&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;http_archive&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">## rules_docker</span></span>
<span class="line">http_archive<span class="token punctuation">(</span></span>
<span class="line">    name <span class="token operator">=</span> <span class="token string">&quot;io_bazel_rules_docker&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    sha256 <span class="token operator">=</span> <span class="token string">&quot;dc97fccceacd4c6be14e800b2a00693d5e8d07f69ee187babfd04a80a9f8e250&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    strip_prefix <span class="token operator">=</span> <span class="token string">&quot;rules_docker-0.14.1&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    urls <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;https://github.com/bazelbuild/rules_docker/releases/download/v0.14.1/rules_docker-v0.14.1.tar.gz&quot;</span><span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">load<span class="token punctuation">(</span></span>
<span class="line">    <span class="token string">&quot;@io_bazel_rules_docker//repositories:repositories.bzl&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    container_repositories <span class="token operator">=</span> <span class="token string">&quot;repositories&quot;</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">container_repositories<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">load<span class="token punctuation">(</span><span class="token string">&quot;@io_bazel_rules_docker//repositories:deps.bzl&quot;</span><span class="token punctuation">,</span> container_deps <span class="token operator">=</span> <span class="token string">&quot;deps&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">container_deps<span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">load<span class="token punctuation">(</span><span class="token string">&quot;@io_bazel_rules_docker//container:pull.bzl&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;container_pull&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">container_pull<span class="token punctuation">(</span></span>
<span class="line">    name <span class="token operator">=</span> <span class="token string">&quot;alpine_linux_amd64&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    registry <span class="token operator">=</span> <span class="token string">&quot;index.docker.io&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    repository <span class="token operator">=</span> <span class="token string">&quot;library/alpine&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    tag <span class="token operator">=</span> <span class="token string">&quot;3.8&quot;</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">## rules_go</span></span>
<span class="line">http_archive<span class="token punctuation">(</span></span>
<span class="line">    name <span class="token operator">=</span> <span class="token string">&quot;io_bazel_rules_go&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    sha256 <span class="token operator">=</span> <span class="token string">&quot;142dd33e38b563605f0d20e89d9ef9eda0fc3cb539a14be1bdb1350de2eda659&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    urls <span class="token operator">=</span> <span class="token punctuation">[</span></span>
<span class="line">        <span class="token string">&quot;https://mirror.bazel.build/github.com/bazelbuild/rules_go/releases/download/v0.22.2/rules_go-v0.22.2.tar.gz&quot;</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token string">&quot;https://github.com/bazelbuild/rules_go/releases/download/v0.22.2/rules_go-v0.22.2.tar.gz&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># ...</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>请注意，bazel 规则加载的顺序并不重要，但我们更愿意将 go 规则留在底部，因为<code>gazelle</code>会在文件底部添加<code>go.mod</code>依赖项。</p><h2 id="构建docker镜像" tabindex="-1"><a class="header-anchor" href="#构建docker镜像"><span>构建Docker镜像</span></a></h2><p>现在，我们必须声明一个创建 docker 镜像的新构建目标。修改<code>cmd/api/BUILD.bazel</code>文件，使其看起来像这样：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line">load<span class="token punctuation">(</span><span class="token string">&quot;@io_bazel_rules_go//go:def.bzl&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;go_binary&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;go_library&quot;</span><span class="token punctuation">)</span></span>
<span class="line">load<span class="token punctuation">(</span><span class="token string">&quot;@io_bazel_rules_docker//container:container.bzl&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;container_image&quot;</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">go_library<span class="token punctuation">(</span></span>
<span class="line">    name <span class="token operator">=</span> <span class="token string">&quot;go_default_library&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    srcs <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;main.go&quot;</span><span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line">    importpath <span class="token operator">=</span> <span class="token string">&quot;github.com/schoren/example-bazel-containers-hasher/cmd/api&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    visibility <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;//visibility:private&quot;</span><span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line">    deps <span class="token operator">=</span> <span class="token punctuation">[</span></span>
<span class="line">        <span class="token string">&quot;@com_github_gorilla_mux//:go_default_library&quot;</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token string">&quot;@org_golang_x_crypto//bcrypt:go_default_library&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">go_binary<span class="token punctuation">(</span></span>
<span class="line">    name <span class="token operator">=</span> <span class="token string">&quot;api&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    embed <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;:go_default_library&quot;</span><span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line">    visibility <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;//visibility:public&quot;</span><span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">container_image<span class="token punctuation">(</span></span>
<span class="line">    name <span class="token operator">=</span> <span class="token string">&quot;image&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    base <span class="token operator">=</span> <span class="token string">&quot;@alpine_linux_amd64//image&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    entrypoint <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;/api&quot;</span><span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line">    files <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;:api&quot;</span><span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>现在，测试新的构建目标：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">bazel build //cmd/api:image</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>上面的命令将构建一个可以导入到 docker 里去的 <code>tar</code>文件。您可以手动调用<code>docker load</code>导入文件，或使用 bazel 来做到这一点：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">bazel run //cmd/api:image</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>现在，如果你运行<code>docker images</code>你会看到这个：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">REPOSITORY      TAG    IMAGE ID            CREATED             SIZE</span>
<span class="line">bazel/cmd/api   image  e793d723ef4f        <span class="token number">50</span> years ago        <span class="token number">10</span>.8MB</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>现在您可以使用 <code>docker run</code>命令来运行镜像：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">docker</span> run <span class="token parameter variable">--rm</span> <span class="token parameter variable">-it</span> <span class="token parameter variable">-p8000:8000</span> bazel/cmd/api:image</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>您可以再次使用<code>curl</code>来测试它是否能够正常工作：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">$ <span class="token function">curl</span> <span class="token parameter variable">-i</span> localhost:8000/hash <span class="token parameter variable">-d</span> <span class="token string">&#39;{&quot;plain&quot;:&quot;text&quot;}&#39;</span></span>
<span class="line">HTTP/1.1 <span class="token number">200</span> OK</span>
<span class="line">Content-Type: application/json</span>
<span class="line">Content-Length: <span class="token number">73</span></span>
<span class="line"></span>
<span class="line"><span class="token punctuation">{</span><span class="token string">&quot;hashed&quot;</span><span class="token builtin class-name">:</span><span class="token string">&quot;<span class="token variable">$2a</span><span class="token variable">$10</span><span class="token variable">$ZqRE</span>.vvvpjHYHvp8HFHO7eGg6RRUS//ctlYPU5sqMYKYzjhAsJIsu&quot;</span><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>让我们提交更改：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">git</span> <span class="token function">add</span> <span class="token builtin class-name">.</span></span>
<span class="line"><span class="token function">git</span> commit <span class="token parameter variable">-m</span> <span class="token string">&quot;Add docker support&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><h2 id="mac-用户注意事项" tabindex="-1"><a class="header-anchor" href="#mac-用户注意事项"><span>Mac 用户注意事项</span></a></h2><p>默认情况下，bazel 会为其运行的平台编译二进制文件。所以，当你运行这些命令时，你最终会得到一个为 MacOS 编译的二进制文件。此二进制文件与 Linux 不兼容。</p><p>但是，docker 镜像是 Linux，因此该文件不能运行。它会显示这样的错误：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">$ <span class="token function">docker</span> run <span class="token parameter variable">--rm</span> <span class="token parameter variable">-it</span> <span class="token parameter variable">-p8000</span> bazel/cmd/api:image</span>
<span class="line">standard_init_linux.go:211: <span class="token builtin class-name">exec</span> user process caused <span class="token string">&quot;exec format error&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>要解决这个问题，您必须在命令中添加一个<code>--platform</code>标志：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">$ bazel run <span class="token parameter variable">--platforms</span><span class="token operator">=</span>@io_bazel_rules_go//go/toolchain:linux_amd64 //cmd/api:image</span>
<span class="line">$ <span class="token function">docker</span> run <span class="token parameter variable">--rm</span> <span class="token parameter variable">-it</span> <span class="token parameter variable">-p8000</span> bazel/cmd/api:image</span>
<span class="line"><span class="token number">2020</span>/03/21 <span class="token number">20</span>:57:17 Start serving<span class="token punctuation">..</span>.</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果您打算把所有的二进制文件都放在 docker 中运行（您应该这样做），您可以使用<a href="https://docs.bazel.build/versions/master/guide.html#where-are-the-bazelrc-files" target="_blank" rel="noopener noreferrer">.bazelrc</a>配置文件配置自动执行此操作的配置。</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">build <span class="token parameter variable">--platforms</span><span class="token operator">=</span>@io_bazel_rules_go//go/toolchain:linux_amd64</span>
<span class="line">run <span class="token parameter variable">--platforms</span><span class="token operator">=</span>@io_bazel_rules_go//go/toolchain:linux_amd64</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div></blockquote><h2 id="发布镜像到-dockerhub" tabindex="-1"><a class="header-anchor" href="#发布镜像到-dockerhub"><span>发布镜像到 DockerHub</span></a></h2><p>您可能注意到您的容器名称是以<code>bazel/</code>为前缀的，这不仅丑陋，而且无法推送到镜像库：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">$ <span class="token function">docker</span> push bazel/cmd/api</span>
<span class="line">The push refers to repository <span class="token punctuation">[</span>docker.io/bazel/cmd/api<span class="token punctuation">]</span></span>
<span class="line">e90f26cebdee: Preparing </span>
<span class="line">7444ea29e45e: Preparing </span>
<span class="line">denied: requested access to the resource is denied</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>此外，在我们的例子中，镜像的标签是构建目标的名称（<code>image</code>）。这在部署此镜像时也不是很有用。</p><p>为了解决第一个问题，我们可以使用<code>cmd/api/BUILD.bazel</code>文件中的<code>container_image</code>规则的<code>repository</code>属性。将<code>&lt;username&gt;</code>替换为您的 <code>DockerHub ID</code> 或任何存储库ID：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line">container_image<span class="token punctuation">(</span></span>
<span class="line">    name <span class="token operator">=</span> <span class="token string">&quot;image&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    base <span class="token operator">=</span> <span class="token string">&quot;@alpine_linux_amd64//image&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    entrypoint <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;/api&quot;</span><span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line">    files <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token string">&quot;:api&quot;</span><span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line">    repository <span class="token operator">=</span> <span class="token string">&quot;&lt;username&gt;&quot;</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>现在，当您运行<code>bazel run //cmd/api:image</code>时，它会将镜像另存为<code>&lt;username&gt;/cmd/api:image</code>。</p><p>同样，要推送我们的镜像，我们可以手动调用<code>docker push &lt;username&gt;/cmd/api</code>命令，我们也可以使用<code>docker_push</code>规则为我们自动执行此操作。将它添加到<code>cmd/api/BUILD.bazel</code>：</p><div class="language-python line-numbers-mode" data-highlighter="prismjs" data-ext="py"><pre><code><span class="line">container_push<span class="token punctuation">(</span></span>
<span class="line">    name <span class="token operator">=</span> <span class="token string">&quot;image-push&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token builtin">format</span> <span class="token operator">=</span> <span class="token string">&quot;Docker&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    image <span class="token operator">=</span> <span class="token string">&quot;:image&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    registry <span class="token operator">=</span> <span class="token string">&quot;index.docker.io&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    repository <span class="token operator">=</span> <span class="token string">&quot;&lt;username&gt;/cmd-api&quot;</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>根据您使用的存储库，它可能支持嵌套存储库（比如：ECR）。在那种情况下，你可以写作<code>&quot;&lt;username&gt;/cmd/api&quot;</code>使之看起来更好。</p></blockquote><p>现在 bazel 可以为你推送镜像了：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">$ bazel run //cmd/api:image-push</span>
<span class="line">INFO: Analyzed target //cmd/api:image-push <span class="token punctuation">(</span><span class="token number">0</span> packages loaded, <span class="token number">0</span> targets configured<span class="token punctuation">)</span>.</span>
<span class="line">INFO: Found <span class="token number">1</span> target<span class="token punctuation">..</span>.</span>
<span class="line">Target //cmd/api:image-push up-to-date:</span>
<span class="line">  bazel-bin/cmd/api/image-push.digest</span>
<span class="line">  bazel-bin/cmd/api/image-push</span>
<span class="line">INFO: Elapsed time: <span class="token number">0</span>.241s, Critical Path: <span class="token number">0</span>.00s</span>
<span class="line">INFO: <span class="token number">0</span> processes.</span>
<span class="line">INFO: Build completed successfully, <span class="token number">1</span> total action</span>
<span class="line">INFO: Build completed successfully, <span class="token number">1</span> total action</span>
<span class="line"><span class="token number">2020</span>/03/21 <span class="token number">18</span>:43:59 Successfully pushed Docker image to index.docker.io/schoren/examples-bazel-containers-hasher-cmd-api:latest</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>提交：</p><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token function">git</span> <span class="token function">add</span> <span class="token builtin class-name">.</span></span>
<span class="line"><span class="token function">git</span> commit <span class="token parameter variable">-m</span> <span class="token string">&quot;Add push support to bazel&quot;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="结论" tabindex="-1"><a class="header-anchor" href="#结论"><span>结论</span></a></h2><p>您现在可以使用 bazel 来管理您的容器镜像开发生命周期：它可以构建镜像并将其推送到镜像库，并具有 bazel 的所有优势：快速且可重现的构建。</p><p>在像这样的小示例中，您可能不会立即看到好处，但在由多个微服务（在容器内运行）组成的更复杂的项目中，这是减少构建和 CI 时间的好方法。</p><h2 id="原文" tabindex="-1"><a class="header-anchor" href="#原文"><span>原文</span></a></h2><p>翻译自：<a href="https://dev.to/schoren/create-container-images-with-bazel-47am" target="_blank" rel="noopener noreferrer">Create Container images with Bazel</a></p>`,90)])])}const u=s(t,[["render",i]]),r=JSON.parse('{"path":"/posts/create_container_images_with_bazel.html","title":"使用 Bazel 创建Go应用程序的Docker容器镜像","lang":"zh-CN","frontmatter":{"date":"2020-01-01T00:00:00.000Z","category":["Go编程"],"tag":["Bazel","Docker","Go"],"sticky":10},"headers":[{"level":2,"title":"示例项目","slug":"示例项目","link":"#示例项目","children":[{"level":3,"title":"POST /hash","slug":"post-hash","link":"#post-hash","children":[]},{"level":3,"title":"POST /compare","slug":"post-compare","link":"#post-compare","children":[]}]},{"level":2,"title":"新建一个 bazel 项目","slug":"新建一个-bazel-项目","link":"#新建一个-bazel-项目","children":[]},{"level":2,"title":"添加一个 hello world 示例代码","slug":"添加一个-hello-world-示例代码","link":"#添加一个-hello-world-示例代码","children":[]},{"level":2,"title":"添加Docker支持","slug":"添加docker支持","link":"#添加docker支持","children":[]},{"level":2,"title":"构建Docker镜像","slug":"构建docker镜像","link":"#构建docker镜像","children":[]},{"level":2,"title":"发布镜像到 DockerHub","slug":"发布镜像到-dockerhub","link":"#发布镜像到-dockerhub","children":[]},{"level":2,"title":"结论","slug":"结论","link":"#结论","children":[]},{"level":2,"title":"原文","slug":"原文","link":"#原文","children":[]}],"git":{"updatedTime":1774788457000,"contributors":[{"name":"tx7do","username":"tx7do","email":"yanglinbo@gmail.com","commits":3,"url":"https://github.com/tx7do"},{"name":"Bobo","username":"Bobo","email":"yanglinbo@gmail.com","commits":1,"url":"https://github.com/Bobo"}],"changelog":[{"hash":"a3e88b19cfead00baa606aa5110b2802dac32768","time":1774788457000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: REBUILD."},{"hash":"64ea488905c4ae4856a8c19fd71addb0d25b1dcc","time":1674900366000,"email":"yanglinbo@gmail.com","author":"tx7do","message":"feat: edit post."},{"hash":"28b1c860291a9d62502f218896ad00387e0c6281","time":1674813672000,"email":"yanglinbo@gmail.com","author":"tx7do","message":"feat: add post."},{"hash":"b44d5c758b08996c10a6a10ff58a8a9d7e1e371d","time":1674808422000,"email":"yanglinbo@gmail.com","author":"tx7do","message":"feat: edit"}]},"filePathRelative":"posts/create_container_images_with_bazel.md","excerpt":"\\n<p>如果你知道<a href=\\"https://bazel.build/\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">Bazel</a>，你就会知道它有多棒：它快速可靠。当您在使用多种服务的项目中工作时，甚至可能使用不同的语言，拥有一个快速可靠的构建系统，更重要的是，生成<a href=\\"https://bazel.build/faq.html#why-would-i-want-to-use-bazel\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">确定性构建</a>是关键。</p>\\n<p>但是，您可能不知道使用它<code>bazel</code>来构建容器镜像是多么容易。您将从使用<code>bazel</code>应用到您的镜像构建过程中获得所有好处。另外，您不必处理丑陋的<code>Dockerfiles</code>。</p>"}');export{u as comp,r as data};
